import{c as r,Z as i,Q as l,j as o,g as a,n,o as s,m as d}from"./chunks/framework.qjzPVSkb.js";const R=JSON.parse('{"title":"RAG","description":"检索增强生成——从外部知识库检索信息后整合给 LLM，解决知识过时和幻觉问题","frontmatter":{"title":"RAG","description":"检索增强生成——从外部知识库检索信息后整合给 LLM，解决知识过时和幻觉问题","difficulty":"intermediate"},"headers":[],"relativePath":"terms/rag.md","filePath":"terms/rag.md"}'),h={name:"terms/rag.md"};function g(m,e,c,f,p,u){const t=i("DifficultyBadge");return l(),o("div",null,[e[0]||(e[0]=a("h1",{id:"rag",tabindex:"-1"},[n("RAG "),a("a",{class:"header-anchor",href:"#rag","aria-label":'Permalink to "RAG"'},"​")],-1)),s(t,{level:"intermediate"}),e[1]||(e[1]=d('<h2 id="一句话解释" tabindex="-1">一句话解释 <a class="header-anchor" href="#一句话解释" aria-label="Permalink to &quot;一句话解释&quot;">​</a></h2><p>RAG（Retrieval-Augmented Generation，检索增强生成）是一种让 LLM 在回答问题时<strong>先从外部知识库检索相关信息</strong>，再将检索到的内容作为上下文拼接给模型的技术方案。它解决了 LLM 知识截止日期过时和&quot;一本正经胡说八道&quot;（幻觉）的两大痛点。</p><h2 id="通俗类比" tabindex="-1">通俗类比 <a class="header-anchor" href="#通俗类比" aria-label="Permalink to &quot;通俗类比&quot;">​</a></h2><p>想象你是一个记者，要写一篇关于&quot;某公司最新财报&quot;的报道。你有两种方式：一是凭记忆写（= 纯 LLM），如果记忆停留在三个月前，写出来的内容就是过时的；二是先去公司的资料库查最新财报，拿在手里边看边写（= RAG），这样写出来的报道就准确且时效性强。RAG 就是给 LLM 配了一个&quot;实时翻书助手&quot;。</p><h2 id="技术定义" tabindex="-1">技术定义 <a class="header-anchor" href="#技术定义" aria-label="Permalink to &quot;技术定义&quot;">​</a></h2><p>RAG 系统的典型工作流程：</p><ol><li><strong>离线索引阶段</strong>：将知识文档（PDF、网页、数据库等）切分成文本块，通过 <a href="/ai-knowledge/terms/embedding.html">Embedding</a> 模型转化为向量，存入 <a href="/ai-knowledge/terms/vector-db.html">向量数据库</a></li><li><strong>在线检索阶段</strong>：用户提问后，将问题同样转化为向量，在向量数据库中执行相似度搜索，召回 Top-K 最相关的文本块</li><li><strong>增强生成阶段</strong>：将召回的文本块作为上下文，与用户问题一起构造 Prompt，发送给 LLM 生成最终回答</li></ol><p>RAG 的核心优势：知识可热更新（不需要重新训练模型）、回答可溯源（能指出信息来自哪个文档）、幻觉可控（有真实文档作为约束）。</p><p>进阶变体包括 <strong>Graph RAG</strong>（用知识图谱组织信息）和 <strong>Agentic RAG</strong>（让 Agent 自主决定检索策略和多轮检索）。</p><h2 id="关联术语" tabindex="-1">关联术语 <a class="header-anchor" href="#关联术语" aria-label="Permalink to &quot;关联术语&quot;">​</a></h2><ul><li><a href="/ai-knowledge/terms/embedding.html">Embedding</a> —— 将文本转为向量的关键技术</li><li><a href="/ai-knowledge/terms/vector-db.html">向量数据库</a> —— 存储和检索向量的基础设施</li><li><a href="/ai-knowledge/terms/llm.html">大语言模型 (LLM)</a> —— RAG 中负责生成回答的模型</li><li><a href="/ai-knowledge/terms/agent.html">Agent</a> —— 更自主的 RAG 变体（Agentic RAG）</li><li><a href="/ai-knowledge/terms/context-window.html">上下文窗口</a> —— RAG 检索结果受限于窗口大小</li></ul><h2 id="延伸阅读" tabindex="-1">延伸阅读 <a class="header-anchor" href="#延伸阅读" aria-label="Permalink to &quot;延伸阅读&quot;">​</a></h2><ul><li>Lewis et al., 2020：<a href="https://arxiv.org/abs/2005.11401" target="_blank" rel="noreferrer">Retrieval-Augmented Generation for Knowledge-Intensive NLP Tasks</a> —— RAG 原始论文</li><li>LangChain RAG 教程：<a href="https://python.langchain.com/docs/tutorials/rag/" target="_blank" rel="noreferrer">Build a RAG application</a></li><li>推荐实践：从简单的单轮 RAG 开始，逐步引入多轮检索、重排序（Re-rank）、查询重写等优化手段。</li></ul>',13))])}const G=r(h,[["render",g]]);export{R as __pageData,G as default};
